//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Table-structure revisions: cellDel/cellIns/cellMerge, deleted/inserted
//! rows, tbl*Change snapshots".
//!
//! Each `#[test]` encodes a Word-compliance constraint drawn from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 about how table-structure tracked-change markup must
//! be serialized (Annex A child ordering) and consumed (accept-all / reject-all
//! text). A FAILING assertion here means stemma DIVERGES from Word — i.e. a real
//! Word-compliance gap — NOT something to be made green by weakening the test.
//!
//! Methodology note (consumption vs. save):
//! - `xmlContains`/`xmlOmits`/ordering checks run against `reserialize()`. stemma
//!   round-trips untouched content byte-verbatim, so these are only valid for
//!   markup the serializer ACTIVELY generates/restructures: child ordering
//!   (Annex A sequence), structural synthesis, opens-clean validity. The
//!   ordering specs below assert the schema sequence, which the serializer must
//!   honour whenever it re-emits the part.
//! - Consumption semantics ("merge state is not a content delete") are asserted
//!   on the READ side via `read_accepted()` / `read_rejected()`.

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal-docx plumbing (mirrors the shared spec-suite prelude) ──

/// Build a valid minimal `.docx`. `body_xml` is the inner content of `<w:body>`
/// (it must already include its own `<w:sectPr/>`); it is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` are additional
/// `word/`-relative parts (e.g. `("styles.xml", "<w:styles…/>")`); each gets a
/// Content_Types override based on a small known map.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Build Content_Types with overrides for any extra parts we know about.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (name, _) in extra_parts {
        let ct = match *name {
            "styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => {
                panic!("make_docx: unknown extra part {other:?} — add its content-type override")
            }
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/word/{name}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // Relationships from document.xml to any extra parts (styles/numbering).
    let mut doc_rels = String::from(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">"#,
    );
    for (idx, (name, _)) in extra_parts.iter().enumerate() {
        let rel_type = match *name {
            "styles.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles"
            }
            "numbering.xml" => {
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering"
            }
            other => panic!("make_docx: unknown extra part {other:?} — add its relationship type"),
        };
        doc_rels.push_str(&format!(
            r#"<Relationship Id="rIdX{idx}" Type="{rel_type}" Target="{name}"/>"#
        ));
    }
    doc_rels.push_str("</Relationships>");

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, content) in extra_parts {
            zip.start_file(format!("word/{name}"), opts).unwrap();
            zip.write_all(content.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip the `.docx` bytes and return `word/document.xml` as a `String`.
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    String::from_utf8_lossy(
        archive
            .get("word/document.xml")
            .expect("document.xml present"),
    )
    .into_owned()
}

/// Parse → serialize (`ExportOptions::default()`) → return `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Accepted-all text content with all whitespace removed.
///
/// The spec rules under test are about which cells' text SURVIVES a resolution,
/// not about how the read-view separates blocks/cells. stemma's `to_text()`
/// joins distinct table cells with whitespace (a correct rendering choice for
/// distinct content); the cell separator is not part of any §17.13.5 rule, so we
/// compare on the concatenated surviving characters to encode the spec rule
/// itself rather than the cosmetic separator.
fn accept_text(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for accept");
    strip_ws(&doc.read_accepted().expect("read_accepted").to_text())
}

/// Rejected-all text content with all whitespace removed (see [`accept_text`]).
fn reject_text(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reject");
    strip_ws(&doc.read_rejected().expect("read_rejected").to_text())
}

/// Remove ASCII/Unicode whitespace so a cell-survival assertion is independent
/// of the read-view's block/cell separator.
fn strip_ws(s: &str) -> String {
    s.chars().filter(|c| !c.is_whitespace()).collect()
}

/// Opens-clean: `validate(bytes)` reports no issues. Returns a human description
/// of the issues if any (empty string when clean).
fn validation_issues(bytes: &[u8]) -> String {
    let report = validate(bytes);
    if report.ok && report.issues.is_empty() {
        String::new()
    } else {
        format!("ok={}, issues={:?}", report.ok, report.issues)
    }
}

/// Assert that `first_open` appears before `second_open` in `xml`, with only XML
/// whitespace between the end of the `first` element and the start of `second`
/// (the `\s*` in the source regex). The ordering regexes all target
/// self-closing markers, so `first` ends at its first `/>`.
///
/// This is the no-regex translation of `<A …/>\s*<B`-style ordering regexes.
fn assert_ordered_adjacent(xml: &str, first_open: &str, second_open: &str, msg: &str) {
    let first_start = xml.find(first_open).unwrap_or_else(|| {
        panic!("{msg}\n  could not find first element opening {first_open:?} in:\n{xml}")
    });
    let first_end = first_start
        + xml[first_start..].find("/>").unwrap_or_else(|| {
            panic!("{msg}\n  first element {first_open:?} is not self-closing in:\n{xml}")
        })
        + 2;
    let between = &xml[first_end..];
    let second_rel = between.find(second_open).unwrap_or_else(|| {
        panic!("{msg}\n  could not find second element {second_open:?} after first in:\n{xml}")
    });
    let gap = &between[..second_rel];
    assert!(
        gap.trim().is_empty(),
        "{msg}\n  expected only whitespace between {first_open:?} and {second_open:?}, found {gap:?} in:\n{xml}"
    );
}

// ─── Tests ─────────────────────────────────────────────────────────────────

#[test]
fn cellmerge_cont_is_merge_state_not_content_delete() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Above</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellMerge w:id="3" w:vMerge="cont"/></w:tcPr><w:p><w:r><w:t>Below</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b),
        "AboveBelow",
        "§17.13.5.3 / §17.18.1 (ST_AnnotationVMerge cont): cellMerge changes only \
         vertical-merge STATE; accepting the merge keeps both cells' content, so \
         'Below' is NOT dropped. refs: ECMA-376 §17.13.5.3, MS-OI29500 §2.1.319, ECMA-376 §17.18.1"
    );
    assert_eq!(
        reject_text(&b),
        "AboveBelow",
        "§17.13.5.3: rejecting reverts the merge STATE; run content is never part \
         of the revision, so both texts remain. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "cellMerge vMerge=cont (ST_AnnotationVMerge) is a conformant CT_CellMergeTrackChange; \
         validate() must report no errors. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
}

#[test]
fn cellmerge_empty_revision_is_ignorable_noop() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellMerge w:id="4"/></w:tcPr><w:p><w:r><w:t>X</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p/><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b),
        "X",
        "§17.13.5.3: a cellMerge lacking both vMerge and vMergeOrig 'can be ignored'; \
         accept changes nothing and 'X' remains. refs: ECMA-376 §17.13.5.3, MS-OI29500 §2.1.319"
    );
    assert_eq!(
        reject_text(&b),
        "X",
        "§17.13.5.3: an ignorable empty cellMerge is a no-op on reject, so 'X' remains. \
         refs: ECMA-376 §17.13.5.3, MS-OI29500 §2.1.319"
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "id-only cellMerge is still a valid CT_CellMergeTrackChange (vMerge/vMergeOrig optional); \
         validate() must report no errors. refs: ECMA-376 §17.13.5.3, MS-OI29500 §2.1.319"
    );
}

#[test]
fn celldel_serializes_before_tcprchange_in_tcpr() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="pct"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="pct"/><w:cellDel w:id="5" w:author="A" w:date="2024-01-01T00:00:00Z"/><w:tcPrChange w:id="6" w:author="A" w:date="2024-01-01T00:00:00Z"><w:tcPr><w:tcW w:w="2500" w:type="pct"/></w:tcPr></w:tcPrChange></w:tcPr><w:p><w:r><w:t>Cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:cellDel[^>]*/>\s*<w:tcPrChange` → ordered-adjacent check.
    assert_ordered_adjacent(
        &xml,
        "<w:cellDel",
        "<w:tcPrChange",
        "CT_TcPr extends CT_TcPrInner and appends tcPrChange after the cell-markup group, \
         so the serializer must emit cellDel before tcPrChange. \
         refs: ECMA-376 Annex A CT_TcPr/CT_TcPrInner, ISO 29500-1 §17.13.5.1, §17.13.5.36",
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "A tcPr honoring the CT_TcPr sequence (cell-markup then tcPrChange) is schema-valid \
         and Word opens it without repair. refs: ECMA-376 Annex A CT_TcPr, ISO 29500-1 §17.13.5.1, §17.13.5.36"
    );
}

#[test]
fn cellmerge_serializes_after_vmerge_before_tcprchange() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="pct"/></w:tblPr><w:tblGrid><w:gridCol w:w="2500"/><w:gridCol w:w="2500"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2500" w:type="pct"/></w:tcPr><w:p><w:r><w:t>One</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2500" w:type="pct"/></w:tcPr><w:p><w:r><w:t>Two</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="2500" w:type="pct"/></w:tcPr><w:p><w:r><w:t>Three</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2500" w:type="pct"/><w:shd w:val="clear" w:color="auto" w:fill="FFFF00"/><w:cellMerge w:id="9" w:author="A" w:date="2024-01-01T00:00:00Z" w:vMerge="cont"/></w:tcPr><w:p><w:r><w:t>Four</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:shd[^>]*/>\s*<w:cellMerge` → ordered-adjacent check.
    assert_ordered_adjacent(
        &xml,
        "<w:shd",
        "<w:cellMerge",
        "shd is a CT_TcPrBase child preceding the EG_CellMarkupElements group, so the \
         serializer must emit shd before cellMerge. \
         refs: ECMA-376 Annex A CT_TcPrBase/CT_TcPrInner/CT_TcPr, ISO 29500-1 §17.13.5.3",
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "A tcPr with formatting children then a single cellMerge marker honors CT_TcPrInner \
         and Word opens it without repair. refs: ECMA-376 Annex A CT_TcPrInner, ISO 29500-1 §17.13.5.3"
    );
}

#[test]
fn cellmerge_text_survives_both_resolutions_and_independent_of_sibling_celldel() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Keep</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellDel w:id="5" w:author="A" w:date="2006-06-01T10:00:00Z"/></w:tcPr><w:p><w:r><w:t>Gone</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Three</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellMerge w:id="6" w:author="A" w:date="2006-06-01T10:00:00Z" w:vMerge="cont"/></w:tcPr><w:p><w:r><w:t>Four</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b),
        "KeepThreeFour",
        "Accept-all: the cellDel sibling 'Gone' is removed (cell no longer exists, §17.13.5.1), \
         but the cellMerge cell 'Four' survives (merge-state only, §17.13.5.3). \
         refs: ECMA-376 §17.13.5.3, §17.13.5.1, MS-OI29500 §2.1.319, §2.1.317"
    );
    assert_eq!(
        reject_text(&b),
        "KeepGoneThreeFour",
        "Reject-all: cellDel is undone so 'Gone' returns; cellMerge merge-state is undone but \
         the cell content 'Four' was never removed; all four cells' text present. \
         refs: ECMA-376 §17.13.5.3, §17.13.5.1"
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "A single cellMerge (and a single cellDel) per cell honors EG_CellMarkupElements (choice, \
         maxOccurs=1); validates without repair. refs: ECMA-376 §17.13.5.3, §17.13.5.1"
    );
}

#[test]
fn trprchange_snapshot_serializes_after_base_row_props_in_ct_trpr_order() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="9576"/></w:tblGrid><w:tr><w:trPr><w:trHeight w:val="600"/><w:trPrChange w:id="3" w:author="A" w:date="2006-06-01T13:39:00Z"><w:trPr><w:trHeight w:val="300"/></w:trPr></w:trPrChange></w:trPr><w:tc><w:tcPr><w:tcW w:w="9576" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Row</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:trHeight[^>]*w:val="600"[^>]*/>\s*<w:trPrChange`. The live
    // trHeight is w:val="600"; the prior snapshot's trHeight (300) is nested
    // inside trPrChange and so comes after it. Locate the live one explicitly.
    assert_ordered_adjacent(
        &xml,
        r#"<w:trHeight w:val="600""#,
        "<w:trPrChange",
        "CT_TrPr serializes the live base row props (trHeight=600) before the trPrChange \
         revision child (Annex A order: base props, then ins/del/trPrChange). \
         refs: ECMA-376 Annex A CT_TrPr, ECMA-376 §17.13.5.37, ISO 29500-1 §17.13.5.37",
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "A trPr honoring CT_TrPr ordering with a trHeight=300 prior snapshot is schema-conformant \
         and validates without repair. refs: ECMA-376 Annex A CT_TrPr, §17.13.5.37"
    );
}

#[test]
fn tblgridchange_prior_grid_serializes_after_live_gridcols() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="1548"/><w:gridCol w:w="8028"/><w:tblGridChange w:id="1"><w:tblGrid><w:gridCol w:w="4788"/><w:gridCol w:w="4788"/></w:tblGrid></w:tblGridChange></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="1548" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="8028" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:gridCol w:w="1548"/>\s*<w:gridCol w:w="8028"/>\s*<w:tblGridChange`.
    // Two ordered-adjacency hops: 1548 → 8028, then 8028 → tblGridChange.
    assert_ordered_adjacent(
        &xml,
        r#"<w:gridCol w:w="1548""#,
        r#"<w:gridCol w:w="8028""#,
        "CT_TblGrid serializes live gridCol 1548 before live gridCol 8028 (gridCol* base sequence). \
         refs: ECMA-376 Annex A CT_TblGrid, ECMA-376 §17.13.5.33, ISO 29500-1 §17.13.5.33",
    );
    assert_ordered_adjacent(
        &xml,
        r#"<w:gridCol w:w="8028""#,
        "<w:tblGridChange",
        "CT_TblGrid serializes the live gridCol definitions before the tblGridChange revision \
         record (Annex A: gridCol* then tblGridChange). \
         refs: ECMA-376 Annex A CT_TblGrid, ECMA-376 §17.13.5.33, ISO 29500-1 §17.13.5.33",
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "A w:tblGrid carrying a tblGridChange prior-grid snapshot is schema-conformant and \
         validates without repair. refs: ECMA-376 Annex A CT_TblGrid, §17.13.5.33"
    );
}

#[test]
fn cellmerge_with_inline_run_edit_resolves_independently_in_same_cell() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>One</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Two</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Three</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellMerge w:id="7" w:author="A" w:date="2006-06-01T10:00:00Z" w:vMerge="cont"/></w:tcPr><w:p><w:r><w:t>Base</w:t></w:r><w:ins w:id="8" w:author="A" w:date="2006-06-01T10:00:00Z"><w:r><w:t>Add</w:t></w:r></w:ins></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b),
        "OneTwoThreeBaseAdd",
        "Accept-all keeps the inline-inserted 'Add'; cellMerge contributes no text change, so \
         the merged cell reads 'BaseAdd' and all cells survive. \
         refs: ECMA-376 §17.13.5.3, §17.13.5.14, §17.13.5.18, MS-OI29500 §2.1.319"
    );
    assert_eq!(
        reject_text(&b),
        "OneTwoThreeBase",
        "Reject-all removes the inline-inserted 'Add' but cellMerge never deleted content, so \
         the cell's pre-existing 'Base' text remains; the cell is not dropped. \
         refs: ECMA-376 §17.13.5.3, §17.13.5.18"
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "A cell with one cellMerge marker plus an inline w:ins honors EG_CellMarkupElements and \
         CT_P content; validates without repair. refs: ECMA-376 §17.13.5.3, §17.13.5.18"
    );
}

#[test]
fn cellmerge_cont_without_vmergeorig_opens_clean_text_survives() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Upper</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellMerge w:id="7" w:vMerge="cont"/></w:tcPr><w:p><w:r><w:t>Lower</w:t></w:r></w:p></w:tc></w:tr><w:sectPr/></w:tbl>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        validation_issues(&b),
        "",
        "§17.13.5.3 example emits cellMerge with only vMerge=cont; omitted vMergeOrig defaults to \
         'rest', so the document is conformant and must validate without repair. \
         refs: ECMA-376 §17.13.5.3, ISO 29500-1 §17.18.1, MS-OI29500 §2.1.319"
    );
    assert_eq!(
        accept_text(&b),
        "UpperLower",
        "cellMerge is a merge-state revision (§17.13.5.3), not a content deletion, so accepting \
         keeps both cells' text. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
    assert_eq!(
        reject_text(&b),
        "UpperLower",
        "Rejecting a merge-state revision reverts only the merge setting, never deletes cell \
         content (§17.13.5.3), so the text remains. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
}

#[test]
fn cellmerge_no_attrs_revision_ignored_baseline_both_resolutions() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellMerge w:id="9"/></w:tcPr><w:p><w:r><w:t>Kept</w:t></w:r></w:p></w:tc></w:tr><w:sectPr/></w:tbl>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        validation_issues(&b),
        "",
        "Both vMerge and vMergeOrig are optional (CT_CellMergeTrackChange, §A.1); a cellMerge with \
         neither is schema-valid and must not require repair. refs: ECMA-376 §17.13.5.3, ISO 29500-1 §17.18.1"
    );
    assert_eq!(
        accept_text(&b),
        "Kept",
        "§17.13.5.3: with neither vMerge nor vMergeOrig the revision can be ignored, so accept \
         leaves the baseline cell text. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
    assert_eq!(
        reject_text(&b),
        "Kept",
        "§17.13.5.3: an ignorable cellMerge revision is a no-op, so reject also leaves the baseline \
         cell text. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
}

#[test]
fn cellmerge_vmerge_rest_split_revision_opens_clean_text_survives() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/><w:cellMerge w:id="3" w:vMerge="rest"/></w:tcPr><w:p><w:r><w:t>Split</w:t></w:r></w:p></w:tc></w:tr><w:sectPr/></w:tbl>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        validation_issues(&b),
        "",
        "§17.18.1 lists 'rest' as a valid ST_AnnotationVMerge value, so a cellMerge vMerge=rest is \
         schema-conformant and must validate without repair. refs: ECMA-376 §17.13.5.3, ISO 29500-1 §17.18.1"
    );
    assert_eq!(
        accept_text(&b),
        "Split",
        "A 'rest' cellMerge is a merge-state (split) revision, not a deletion (§17.13.5.3), so \
         accept keeps the cell text. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
    assert_eq!(
        reject_text(&b),
        "Split",
        "Rejecting a split merge-state revision reverts only the merge setting (§17.13.5.3), so the \
         cell text remains. refs: ECMA-376 §17.13.5.3, §17.18.1"
    );
}

#[test]
fn row_del_independent_of_inner_inserted_run_content() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="4788"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Keep</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:trPr><w:del w:id="4" w:author="A" w:date="2021-01-01T00:00:00Z"/></w:trPr><w:tc><w:tcPr><w:tcW w:w="4788" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Base</w:t></w:r><w:ins w:id="5" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Added</w:t></w:r></w:ins></w:p></w:tc></w:tr><w:sectPr/></w:tbl>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b),
        "Keep",
        "Accepting the row deletion (§17.13.5.12) removes the entire second row and all its content, \
         leaving only the surviving row's text. refs: ECMA-376 §17.13.5.12, §17.13.5.18, ISO 29500-1 §17.13.5.12"
    );
    assert_eq!(
        reject_text(&b),
        "KeepBase",
        "Rejecting un-deletes the row (§17.13.5.12) but independently rejects the inner w:ins \
         (§17.13.5.18), dropping 'Added' so only 'Base' remains in the restored row. \
         refs: ECMA-376 §17.13.5.12, §17.13.5.18"
    );
    assert_eq!(
        validation_issues(&b),
        "",
        "Independent row-del and inline-ins revisions with valid ids are conformant and must \
         validate without repair. refs: ECMA-376 §17.13.5.12, §17.13.5.18"
    );
}
